let charts = {};
const currency = v => new Intl.NumberFormat('en-IN', {
  style: 'currency',
  currency: 'INR',
  maximumFractionDigits: 0
}).format(v || 0);
function updateDashboard(model) {
  // Safety check: if no products, show the "Awaiting" message
  if (!model || !model.report_products || model.report_products.length === 0) {
    console.log("No data yet...");
    return;
  }
  const products = model.report_products || [];
  const customers = model.report_customers || [];
  const dse = model.report_dse || [];
  const tiers = model.report_tiers || [];
  document.getElementById('sync-status').innerText = "Live Audit: " + new Date().toLocaleTimeString();

  // 1. Calculations with safety checks
  const totalDisc = products.reduce((acc, p) => acc + parseFloat(p["Total Scheme Disc"] || 0), 0);
  const totalRev = products.reduce((acc, p) => acc + parseFloat(p["Total Net Amt"] || 0), 0);
  const roi = totalRev > 0 ? (totalDisc / totalRev * 100).toFixed(1) : "0.0";
  const topTier = tiers.length > 0 ? tiers.sort((a, b) => b["Total Discount Amount"] - a["Total Discount Amount"])[0]["Scheme Tier"] : "None";
  const totalInvoices = tiers.reduce((acc, t) => acc + (parseInt(t["No. of invoices this scheme was applied to"]) || 0), 0);

  // 2. Update KPI Cards
  document.getElementById('kpi-container').innerHTML = `
        <div class="kpi-card">
            <div class="kpi-label">Total Discount Given</div>
            <div class="kpi-value purple-glow">${currency(totalDisc)}</div>
            <div class="kpi-sub">Across all schemes</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-label">Net Revenue (Scheme Items)</div>
            <div class="kpi-value" style="color: var(--accent-revenue)">${currency(totalRev)}</div>
            <div class="kpi-sub">ROI: ${roi}% burn</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-label">Top Scheme Rule</div>
            <div class="kpi-value" style="font-size: 13px; color: #fff; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${topTier}</div>
            <div class="kpi-sub">Most utilized rule</div>
        </div>
        <div class="kpi-card">
            <div class="kpi-label">Invoices Impacted</div>
            <div class="kpi-value">${totalInvoices}</div>
            <div class="kpi-sub">Customer Reach</div>
        </div>
    `;

  // 3. Update Lists
  document.getElementById('customer-list').innerHTML = customers.slice(0, 10).map(c => `
        <div class="list-item">
            <div class="item-name">${c.Customer}<span class="item-sub">${c["Matching Items"]} line items</span></div>
            <div class="item-val">${currency(c["Total Disc Received"])}</div>
        </div>
    `).join('');
  document.getElementById('product-list').innerHTML = products.sort((a, b) => b["Total Net Amt"] - a["Total Net Amt"]).slice(0, 10).map(p => `
        <div class="list-item">
            <div class="item-name">${p.Product}<span class="item-sub">Qty: ${p["Total Qty"]}</span></div>
            <div class="item-val" style="color: #fff">${currency(p["Total Net Amt"])}</div>
        </div>
    `).join('');

  // 4. Update Charts
  renderCharts(dse, tiers);
}
function renderCharts(dse, tiers) {
  if (charts.dse) charts.dse.destroy();
  const ctxDse = document.getElementById('dseChart');
  if (ctxDse) {
    charts.dse = new Chart(ctxDse, {
      type: 'bar',
      data: {
        labels: dse.map(d => d["Salesman (DSE)"]),
        datasets: [{
          label: 'Discount',
          data: dse.map(d => d["Total Discount Given"]),
          backgroundColor: '#bf40bf',
          borderRadius: 5
        }, {
          label: 'Sales',
          data: dse.map(d => d["Total Scheme Sale"]),
          backgroundColor: '#2188ff',
          borderRadius: 5
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
          y: {
            grid: {
              color: '#333'
            },
            ticks: {
              color: '#888'
            }
          },
          x: {
            ticks: {
              color: '#888'
            }
          }
        },
        plugins: {
          legend: {
            labels: {
              color: '#fff'
            }
          }
        }
      }
    });
  }
  if (charts.tier) charts.tier.destroy();
  const ctxTier = document.getElementById('tierChart');
  if (ctxTier) {
    charts.tier = new Chart(ctxTier, {
      type: 'doughnut',
      data: {
        labels: tiers.map(t => t["Scheme Tier"]),
        datasets: [{
          data: tiers.map(t => t["Total Discount Amount"]),
          backgroundColor: ['#bf40bf', '#2188ff', '#3fb950', '#d29922', '#f85149'],
          borderWidth: 0
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        cutout: '70%',
        plugins: {
          legend: {
            position: 'bottom',
            labels: {
              color: '#888',
              boxWidth: 10
            }
          }
        }
      }
    });
  }
}

// Appsmith Listeners
appsmith.onReady(() => {
  updateDashboard(appsmith.model);
});

// Catch model changes
window.onmessage = event => {
  if (event.data.type === 'UPDATE_MODEL') {
    updateDashboard(appsmith.model);
  }
};

